  1023→                    case '\t':
  1024→                    case '\0':
  1025→                        done=1;
  1026→                        break;
  1027→                    case '"':
  1028→                        inq=1;
  1029→                        break;
  1030→                    case '\'':
  1031→                        insq=1;
  1032→                        break;
